parameters.text:
=You are a Customer Success Coordinator. Review the order data below and generate an internal email summary for the fulfillment team.

Rules:
- Respond ONLY with a raw JSON object — no markdown, no code fences, no explanation, no preamble.
- The JSON must have exactly two keys: "subject" and "body".
- "subject": a short, descriptive email subject line.
- "body": the full plain-text email body with order summary, signed off as 'Customer Success Team'.

Order Data:
Order ID: {{ $json.OrderID }}
Customer Name: {{ $json.CustomerName }}
Product: {{ $json.Product }}
Quantity: {{ $json.Quantity }}
Price: {{ $json.Price }}
Order Date: {{ $json.FormattedOrderDate }}
Status: {{ $json.Status }}

Respond with ONLY this structure and nothing else:
{"subject": "...", "body": "..."}

parameters.jsCode:
const items = [];

for (const item of $input.all()) {
  let raw = (item.json.output || '').trim();

  // Strip markdown code fences if the model wraps output in ```json ... ```
  raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    // Fallback: regex extraction if JSON parse fails
    const subjectMatch = raw.match(/"subject"\s*:\s*"((?:[^"\\]|\\[\s\S])*)"/i);
    const bodyMatch = raw.match(/"body"\s*:\s*"((?:[^"\\]|\\[\s\S])*)"/i);
    parsed = {
      'Email Subject': subjectMatch ? subjectMatch[1].replace(/\\n/g, '\n') : 'No subject',
      'Email Body': bodyMatch ? bodyMatch[1].replace(/\\n/g, '\n') : raw
    };
  }

  items.push({
    json: {
      'Email Subject': parsed.subject || '',
      'Email Body': parsed.body || ''
    }
  });
}

return items;

const items = [];

function getOrdinal(day) {
  if (day >= 11 && day <= 13) return day + 'th';
  switch (day % 10) {
    case 1: return day + 'st';
    case 2: return day + 'nd';
    case 3: return day + 'rd';
    default: return day + 'th';
  }
}

const monthNames = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December'
];

for (const item of $input.all()) {
  const raw = item.json.OrderDate;
  let formatted = raw;

  const serial = Number(raw);
  if (!isNaN(serial) && serial > 1000) {
    // Google Sheets epoch: December 30, 1899
    const date = new Date((serial - 25569) * 86400 * 1000);
    const day = date.getUTCDate();
    const month = monthNames[date.getUTCMonth()];
    const year = date.getUTCFullYear();
    formatted = `${month} ${getOrdinal(day)} ${year}`;
  } else if (raw) {
    // Already a string date — parse and reformat
    const date = new Date(raw);
    if (!isNaN(date.getTime())) {
      const day = date.getUTCDate();
      const month = monthNames[date.getUTCMonth()];
      const year = date.getUTCFullYear();
      formatted = `${month} ${getOrdinal(day)} ${year}`;
    }
  }

  items.push({
    json: {
      ...item.json,
      FormattedOrderDate: formatted
    }
  });
}

return items;
